public void Recommendations_WithConflictingOptionalMods_ContainsAllOptions()
{
    options!.with_recommends              = true;
    options.proceed_with_inconsistencies = true;
    var recommendedA = generator!.GenerateRandomModule(identifier: "RecommendedA");
    var recommendedB = generator.GenerateRandomModule(identifier: "RecommendedB",
        conflicts: new List<RelationshipDescriptor>
        {
            new ModuleRelationshipDescriptor { name = recommendedA.identifier }
        });
    var recommendedC = generator.GenerateRandomModule(identifier: "RecommendedC");
    var recommender = generator.GenerateRandomModule(identifier: "Recommender");
    recommender.recommends = new List<RelationshipDescriptor>
    {
        new ModuleRelationshipDescriptor { name = recommendedA.identifier },
        new ModuleRelationshipDescriptor { name = recommendedB.identifier },
        new ModuleRelationshipDescriptor { name = recommendedC.identifier },
    };

    var user = new NullUser();
    using (var repo = new TemporaryRepository(recommender.ToJson(),
                                              recommendedA.ToJson(),
                                              recommendedB.ToJson(),
                                              recommendedC.ToJson()))
    using (var repoData = new TemporaryRepositoryData(user, repo.repo))
    {
        var registry = new CKAN.Registry(repoData.Manager, repo.repo);
        var relationship_resolver = new RelationshipResolver(new List<CkanModule> { recommender },
                                                             null, options, registry, game, crit);
        var dependencies = relationship_resolver.Dependencies().ToHashSet();

        CollectionAssert.AreEquivalent(new[] { recommendedA, recommendedB, recommendedC },
                                       relationship_resolver.Recommendations(dependencies));
    }
}

